const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
const sinceISO = weekAgo.toISOString().split('T')[0];
const untilISO = now.toISOString().split('T')[0];
const owner = $node['Config'].json['REPO_OWNER'];
const repo = $node['Config'].json['REPO_NAME'];
return [{ json: { since: sinceISO, until: untilISO, owner, repo, sinceISO, untilISO } }];

const commits = $input.all();
const commitsData = $node['Fetch Commits (7d)'].data;
const issuesData = $node['Fetch Closed Issues (7d)'].data;
const prsData = $node['Fetch Merged PRs (7d)'].data;

const sinceISO = $node['Calculate Week Range'].json['sinceISO'];
const untilISO = $node['Calculate Week Range'].json['untilISO'];
const repoOwner = $node['Config'].json['REPO_OWNER'];
const repoName = $node['Config'].json['REPO_NAME'];
const lang = $node['Config'].json['LANGUAGE'] || 'EN';

const commitList = (commitsData || [])
  .filter(c => c.commit && c.commit.author && c.commit.author.date >= sinceISO && c.commit.author.date <= untilISO + 'T23:59:59Z')
  .map(c => ({
    message: (c.commit.message || '').split('\n')[0],
    author: c.commit.author.name,
    date: c.commit.author.date,
    sha: c.sha
  }));

const mergedPRs = (prsData || []).filter(pr => 
  pr.merged_at && pr.merged_at >= sinceISO + 'T00:00:00Z'
).map(pr => ({
  title: pr.title,
  number: pr.number,
  user: pr.user?.login,
  merged_at: pr.merged_at
}));

const closedIssues = (issuesData || []).filter(iss => 
  !iss.pull_request && iss.closed_at && iss.closed_at >= sinceISO + 'T00:00:00Z'
).map(iss => ({
  title: iss.title,
  number: iss.number,
  labels: (iss.labels || []).map(l => l.name),
  closed_at: iss.closed_at
}));

return [{ json: {
  repo: `${repoOwner}/${repoName}`,
  since: sinceISO,
  until: untilISO,
  language: lang,
  commits: commitList,
  mergedPRs,
  closedIssues
}}];

