    return 'Tu es un chef de projet technique expert. Rédige un résumé narratif hebdomadaire concis et engageant en Markdown pour le dépôt GitHub. Utilise des titres (##), des listes à puces, et gras pour les chiffres clés. Structure: (1) Aperçu de la semaine, (2) Points forts, (3) Commits, (4) Problèmes fermés, (5) PRs fusionnées, (6) Remarques finales.';
  }
}}

=[{"role":"user","content": {{
  const data = $node['Aggregate GitHub Data'].json;
  const isEN = data['language'] !== 'FR';
  const commitLines = (data['commits'] || []).slice(0, 10).map(c => `- ${c.message} (${c.author}, ${c.date.split('T')[0]})`).join('
');
  const issueLines = (data['closedIssues'] || []).slice(0, 10).map(i => `- #${i['number']}: ${i['title']}` + (i['labels'].length ? ` [${i['labels'].join(', ')}]` : '')).join('
');
  const prLines = (data['mergedPRs'] || []).slice(0, 10).map(p => `- #${p['number']}: ${p['title']} (by @${p['user']})`).join('
');
  const langHint = isEN ? '' : '

**Respond in French.**';
  return `Generate a weekly dev summary for repository **${data['repo']}** covering ${data['since']} to ${data['until']}.${langHint}

## Commits (${data['commits'].length} total)
${commitLines || 'No commits this week.'}

## Closed Issues (${data['closedIssues'].length} total)
${issueLines || 'No issues closed this week.'}

## Merged PRs (${data['mergedPRs'].length} total)
${prLines || 'No PRs merged this week.'}`;
}}]
